from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismMonkeyPatchNode(BaseNode):
    name = "Prism: Monkey-Patch Function"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("target_path", "string", widget_type="text", default="core.entities.getAssetDescription")
        self.add_input("replacement_code", "string", widget_type="text_area", default="def replacement(self, *args, **kwargs):\n    return 'patched value'")
        self.add_input("force", "bool", widget_type="bool", default=True)
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        target_path = inputs.get('target_path') or ''
        code = inputs.get('replacement_code') or ''
        force = bool(inputs.get('force', True))
        if core is None or not target_path or not code:
            self.log_error("Need core, target_path and replacement_code.")
            return {'success': False}
        try:
            # Resolve dotted target on the core object
            obj = core
            parts = target_path.split('.')
            if parts[0] == 'core':
                parts = parts[1:]
            for p in parts[:-1]:
                obj = getattr(obj, p)
            target = getattr(obj, parts[-1])
            # Compile replacement
            ns = {}
            exec(code, ns)
            repl = ns.get('replacement')
            if repl is None:
                self.log_error("replacement_code must define a function named 'replacement'.")
                return {'success': False}
            core.plugins.monkeyPatch(target, repl, self, force=force)
            self.log_success(f"Patched {target_path}")
            await self.set_output('exec_out', True)
            return {'success': True}
        except Exception as e:
            self.log_error(f"monkeyPatch failed: {e}")
            return {'success': False}

def register_node():
    return PrismMonkeyPatchNode
